#!/usr/bin/perl
use strict;
use warnings;
use CGI;

my $cgi = CGI->new();
my $log_dir = '/var/log'; # Define log directory here
my $filename = $cgi->param('logfile');

if (!$filename) {
    print "Content-type: text/html\n\n";
    print "<h1>Log Viewer</h1>";
    print "<p>Please provide a log file name.</p>";
} else {
    my $full_path = "$log_dir/$filename";
    if (-f $full_path && -r $full_path) { # Check if file exists and is readable
        open(my $FH, '<', $full_path) or die "Can't open $full_path: $!";
        print "Content-type: text/html\n\n";
        print "<h1>Log File: $filename</h1>";
        while (my $line = <$FH>) {
            print "$line";
        }
    } else {
        print "Content-type: text/html\n\n";
        print "<h1>Error</h1>";
        print "<p>Invalid log file name or access denied.</p>";
    }
}